 1	import { type MouseEvent, type Ref, useState } from 'react';
 2	
 3	import { MenuToggle, type MenuToggleElement, Select, SelectOption } from '@patternfly/react-core';
 4	import { t } from '@utils/i18n';
 5	
 6	import { TimeRangeOptions, valueToLabel } from '../utils/timeRangeOptions';
 7	
 8	const HeaderActions = ({
 9	  selectedTimeRange,
10	  setSelectedTimeRange,
11	  showAll = false,
12	}: {
13	  selectedTimeRange: TimeRangeOptions;
14	  setSelectedTimeRange: (range: TimeRangeOptions) => void;
15	  showAll?: boolean;
16	}) => {
17	  const [isOpen, setIsOpen] = useState(false);
18	
19	  const onSelect = (_event: MouseEvent | undefined, value: string | number | undefined) => {
20	    setSelectedTimeRange(value as TimeRangeOptions);
21	    setIsOpen(false);
22	  };
23	
24	  const onToggleClick = () => {
25	    setIsOpen(!isOpen);
26	  };
27	
28	  const toggle = (toggleRef: Ref<MenuToggleElement>) => (
29	    <MenuToggle
30	      ref={toggleRef}
31	      onClick={onToggleClick}
32	      isExpanded={isOpen}
33	      className="forklift-overview__cards-select"
34	    >
35	      {valueToLabel[selectedTimeRange]}
36	    </MenuToggle>
37	  );
38	
39	  return (
40	    // Custom select does not support the complex toggle being used here
41	    // eslint-disable-next-line no-restricted-syntax
42	    <Select
43	      isOpen={isOpen}
44	      onSelect={onSelect}
45	      selected={selectedTimeRange}
46	      aria-label={t('Select time range')}
47	      toggle={toggle}
48	      onOpenChange={setIsOpen}
49	    >
50	      <SelectOption value={TimeRangeOptions.Last24H}>
51	        {valueToLabel[TimeRangeOptions.Last24H]}
52	      </SelectOption>
53	      <SelectOption value={TimeRangeOptions.Last10Days}>
54	        {valueToLabel[TimeRangeOptions.Last10Days]}
55	      </SelectOption>
56	      <SelectOption value={TimeRangeOptions.Last31Days}>
57	        {valueToLabel[TimeRangeOptions.Last31Days]}
58	      </SelectOption>
59	      {showAll && (
60	        <SelectOption value={TimeRangeOptions.All}>
61	          {valueToLabel[TimeRangeOptions.All]}
62	        </SelectOption>
63	      )}
64	    </Select>
65	  );
66	};
67	
68	export default HeaderActions;

